parameters.query:
INSERT INTO julia_lead_memory (
  phone,

  contact_id,
  conversation_id,
  account_id,
  inbox_id,

  lead_name,
  company_name,

  lead_source_type,
  source_label,

  lead_status,
  fit_score,

  nome_responsavel,
  origem_clientes,
  principal_gargalo,
  interesse_em_crescer,
  tem_agencia,

  responsavel_confirmado,
  responsavel_terceiro,
  contato_responsavel,
  origem_clientes_identificada,
  gargalo_identificado,
  pedido_preco,
  pedido_detalhes,
  handoff_realizado,
  ultima_pergunta_feita,

  motivo_score,
  resumo_conversa,
  proximo_passo,
  observacoes,

  last_message,
  last_response,
  last_message_id,

  tags_adicionar,
  tags_remover,
  raw_result,

  first_seen_at,
  last_seen_at,
  updated_at
)
VALUES (
  '{{ String($('RESPONDER').item.json.lead.phone || "").replace(/\\/g, "\\\\").replace(/'/g, "''") }}',

  {{ $('RESPONDER').item.json.chatwoot.contact_id || $('RESPONDER').item.json.lead.id || 'NULL' }},
  {{ $('RESPONDER').item.json.chatwoot.conversation_id || 'NULL' }},
  {{ $('RESPONDER').item.json.chatwoot.account_id || 'NULL' }},
  {{ $('RESPONDER').item.json.chatwoot.inbox_id || 'NULL' }},

  '{{ String($('RESPONDER').item.json.lead.name || "").replace(/\\/g, "\\\\").replace(/'/g, "''") }}',
  '{{ String($('RESPONDER').item.json.parsed_output?.empresa || $('RESPONDER').item.json.lead.empresa_detectada || $('RESPONDER').item.json.lead.company_name || $('RESPONDER').item.json.crm_update?.empresa || "").replace(/\\/g, "\\\\").replace(/'/g, "''") }}',

  '{{ String($('RESPONDER').item.json.parsed_output?.lead_source_type || $('RESPONDER').item.json.crm_update?.lead_source_type || $('RESPONDER').item.json.lead.source_type || $('RESPONDER').item.json.lead.source || "").replace(/\\/g, "\\\\").replace(/'/g, "''") }}',
  '{{ String($('RESPONDER').item.json.lead.source_label || $('RESPONDER').item.json.conversation?.source_label || "").replace(/\\/g, "\\\\").replace(/'/g, "''") }}',

  '{{ (() => {
    const j = $('RESPONDER').item.json;
    const p = j.parsed_output || j.agent?.result || {};
    const finalHandoff = j.should_handoff === true || p.handoff_humano === true;

    let status = String(p.status || j.crm_update?.lead_status || j.lead?.lead_status || "").trim();

    if (status === "QUALIFICADO_HUMANO" && !finalHandoff) {
      status = "EM_ANDAMENTO";
    }

    return status.replace(/\\/g, "\\\\").replace(/'/g, "''");
  })() }}',

  {{ (() => {
    const j = $('RESPONDER').item.json;
    const p = j.parsed_output || j.agent?.result || {};
    const value = p.score_de_0_a_100 ?? j.crm_update?.fit_score ?? j.lead?.fit_score;
    return Number.isFinite(Number(value)) ? Number(value) : 'NULL';
  })() }},

  '{{ String($('RESPONDER').item.json.parsed_output?.nome_responsavel || $('RESPONDER').item.json.crm_update?.nome_responsavel || $('RESPONDER').item.json.lead.responsible_name || "").replace(/\\/g, "\\\\").replace(/'/g, "''") }}',
  '{{ String($('RESPONDER').item.json.parsed_output?.origem_clientes || $('RESPONDER').item.json.crm_update?.origem_clientes || $('RESPONDER').item.json.lead.origem_clientes || "").replace(/\\/g, "\\\\").replace(/'/g, "''") }}',
  '{{ String($('RESPONDER').item.json.parsed_output?.principal_gargalo || $('RESPONDER').item.json.crm_update?.principal_gargalo || $('RESPONDER').item.json.lead.principal_gargalo || "").replace(/\\/g, "\\\\").replace(/'/g, "''") }}',
  '{{ String($('RESPONDER').item.json.parsed_output?.interesse_em_crescer || $('RESPONDER').item.json.crm_update?.interesse_em_crescer || $('RESPONDER').item.json.lead.interesse_em_crescer || "").replace(/\\/g, "\\\\").replace(/'/g, "''") }}',

  {{ (() => {
    const j = $('RESPONDER').item.json;
    const p = j.parsed_output || j.agent?.result || {};
    const value = p.tem_agencia ?? j.crm_update?.tem_agencia ?? j.lead?.tem_agencia;

    if (value === null || value === undefined || value === "") return 'NULL';

    const text = String(value).trim().toLowerCase();

    if (value === true || value === 1 || ["true", "sim", "yes", "1"].includes(text)) return 1;
    if (value === false || value === 0 || ["false", "não", "nao", "no", "0"].includes(text)) return 0;

    return 'NULL';
  })() }},

  {{ (() => {
    const j = $('RESPONDER').item.json;
    const p = j.parsed_output || j.agent?.result || {};

    const name =
      p.nome_responsavel ||
      j.crm_update?.nome_responsavel ||
      j.lead?.responsible_name ||
      "";

    const value = p.responsavel_confirmado;
    const text = String(value).trim().toLowerCase();

    return value === true || value === 1 || ["true", "sim", "yes", "1"].includes(text) || Boolean(String(name).trim()) ? 1 : 0;
  })() }},

  {{ (() => {
    const j = $('RESPONDER').item.json;
    const p = j.parsed_output || j.agent?.result || {};

    const value = p.responsavel_terceiro;
    const text = String(value).trim().toLowerCase();

    return value === true || value === 1 || ["true", "sim", "yes", "1"].includes(text) ? 1 : 0;
  })() }},

  '{{ String($('RESPONDER').item.json.parsed_output?.contato_responsavel || $('RESPONDER').item.json.crm_update?.telefone_responsavel || $('RESPONDER').item.json.lead.responsible_phone || "").replace(/\\/g, "\\\\").replace(/'/g, "''") }}',

  {{ (() => {
    const j = $('RESPONDER').item.json;
    const p = j.parsed_output || j.agent?.result || {};

    const origem =
      p.origem_clientes ||
      j.crm_update?.origem_clientes ||
      j.lead?.origem_clientes ||
      "";

    const value = p.origem_clientes_identificada;
    const text = String(value).trim().toLowerCase();

    return value === true || value === 1 || ["true", "sim", "yes", "1"].includes(text) || Boolean(String(origem).trim()) ? 1 : 0;
  })() }},

  {{ (() => {
    const j = $('RESPONDER').item.json;
    const p = j.parsed_output || j.agent?.result || {};

    const gargalo =
      p.principal_gargalo ||
      j.crm_update?.principal_gargalo ||
      j.lead?.principal_gargalo ||
      "";

    const value = p.gargalo_identificado;
    const text = String(value).trim().toLowerCase();

    return value === true || value === 1 || ["true", "sim", "yes", "1"].includes(text) || Boolean(String(gargalo).trim()) ? 1 : 0;
  })() }},

  {{ (() => {
    const j = $('RESPONDER').item.json;
    const p = j.parsed_output || j.agent?.result || {};
