const NORMALIZA_ENTRADA_CHATWOOT_VERSION = "v5_clean_only_labels_and_input";

const firstItem = $("Webhook").first()?.json || {};
const envelope = Array.isArray(firstItem) ? (firstItem[0] || {}) : firstItem;
const body = envelope.body && typeof envelope.body === "object" ? envelope.body : envelope;
const headers = envelope.headers || {};

const JULIA_LABELS = new Set(["01-julia-conversando"]);
const HUMAN_LABELS = new Set(["01-humano-assumiu", "humano-assumiu"]);
const OPTOUT_LABELS = new Set(["99-optout"]);

const SOURCE_LABELS = {
  prospeccao_ativa: "00-prospeccao-ativa",
  lead_trafego: "00-lead-trafego",
  lead_organico: "00-lead-organico",
};

function clean(value) {
  if (value === undefined || value === null) return "";
  return String(value).trim();
}

function cleanText(value) {
  return clean(value)
    .replace(/\[object Object\]/gi, "")
    .replace(/[\u200B-\u200D\u2060\uFEFF]/g, " ")
    .replace(/\uFFFD/g, " ")
    .replace(/\r\n/g, "\n")
    .replace(/\r/g, "\n")
    .replace(/[ \t]+/g, " ")
    .replace(/\n{3,}/g, "\n\n")
    .trim();
}

function onlyDigits(value) {
  return clean(value).replace(/\D/g, "");
}

function firstFilled(...values) {
  for (const value of values) {
    const text = clean(value);
    if (text) return text;
  }
  return "";
}

function normalizeLabel(label) {
  return clean(label).toLowerCase();
}

function normalizeLabels(value) {
  if (Array.isArray(value)) {
    return value.map(label => clean(label)).filter(Boolean);
  }

  if (value && typeof value === "object") {
    if (Array.isArray(value.payload)) return normalizeLabels(value.payload);
    if (Array.isArray(value.labels)) return normalizeLabels(value.labels);
  }

  if (typeof value === "string") {
    return value.split(",").map(label => clean(label)).filter(Boolean);
  }

  return [];
}

function getLabelsFromListaEtiquetas() {
  try {
    const items = $("Lista Etiquetas").all();

    for (const item of items) {
      const json = item.json || {};
      const labels = normalizeLabels(json.payload || json.labels || json);
      if (labels.length) return labels;
    }

    return [];
  } catch (error) {
    return [];
  }
}

function detectLeadSource(labels = []) {
  const set = new Set(labels.map(normalizeLabel));

  if (set.has(SOURCE_LABELS.lead_trafego)) {
    return {
      source_type: "lead_trafego",
      source_label: SOURCE_LABELS.lead_trafego,
      playbook_mode: "lead_trafego",
      source_description: "Lead vindo de anúncio, formulário ou campanha paga."
    };
  }

  if (set.has(SOURCE_LABELS.lead_organico)) {
    return {
      source_type: "lead_organico",
      source_label: SOURCE_LABELS.lead_organico,
      playbook_mode: "lead_organico",
      source_description: "Lead vindo de canal orgânico, link da bio, perfil, conteúdo ou indicação espontânea."
    };
  }

  if (set.has(SOURCE_LABELS.prospeccao_ativa)) {
    return {
      source_type: "prospeccao_ativa",
      source_label: SOURCE_LABELS.prospeccao_ativa,
      playbook_mode: "prospeccao_ativa",
      source_description: "Lead vindo de prospecção ativa ou abordagem iniciada pela Convertix."
    };
  }

  return {
    source_type: "indefinido",
    source_label: "",
    playbook_mode: "indefinido",
    source_description: "Origem não identificada pelas etiquetas atuais."
  };
}

function nowIso() {
  return new Date().toISOString();
}

function ignored(reason, extra = {}) {
  return [{
    json: {
      action: "ignore",
      event: clean(body.event),

      ignore: {
        reason,
        ...extra,
      },

      routing: {
        should_process: false,
        should_reply: false,
        should_handoff: false,
        route_action: "ignore",
        channel: "chatwoot_whatsapp",
      },

      conversation: {
        labels,
        has_julia_label: hasJuliaLabel,
        has_human_label: hasHumanLabel,
        has_optout_label: hasOptoutLabel,
        lead_source_type: leadSource.source_type,
        source_label: leadSource.source_label,
        playbook_mode: leadSource.playbook_mode,
      },

      chatwoot: {
        account_id: body.account?.id || body.conversation?.account_id || null,
        inbox_id: body.inbox?.id || body.conversation?.inbox_id || null,
        conversation_id: body.conversation?.id || null,
        contact_id: body.sender?.id || body.conversation?.meta?.sender?.id || null,
        message_id: body.id || null,
        delivery_id: headers["x-chatwoot-delivery"] || "",
      },

      debug: {
        normaliza_entrada_chatwoot_version: NORMALIZA_ENTRADA_CHATWOOT_VERSION,
        reason,
        labels,
        has_julia_label: hasJuliaLabel,
        has_human_label: hasHumanLabel,
        has_optout_label: hasOptoutLabel,
        should_process_by_labels: shouldProcessByLabels,
        lead_source_type: leadSource.source_type,
        source_label: leadSource.source_label,
      },
    },
  }];
}

const labels = getLabelsFromListaEtiquetas();
const labelsLower = labels.map(normalizeLabel);

const hasJuliaLabel = labelsLower.some(label => JULIA_LABELS.has(label));
const hasHumanLabel = labelsLower.some(label => HUMAN_LABELS.has(label));
const hasOptoutLabel = labelsLower.some(label => OPTOUT_LABELS.has(label));

const shouldProcessByLabels = hasJuliaLabel && !hasHumanLabel && !hasOptoutLabel;
const leadSource = detectLeadSource(labels);

const conversation = body.conversation || {};
const messages = Array.isArray(conversation.messages) ? conversation.messages : [];

const primaryMessage =
  messages.find(message => String(message.id) === String(body.id)) ||
  messages[0] ||
  {};

const sender = body.sender || conversation.meta?.sender || primaryMessage.sender || {};

const event = clean(body.event);
const messageType = clean(body.message_type);
const numericMessageType = primaryMessage.message_type;
const senderType = clean(primaryMessage.sender_type || sender.type);

const isIncoming =
  messageType === "incoming" ||
  numericMessageType === 0 ||
  senderType.toLowerCase() === "contact";

const isPrivate = body.private === true || primaryMessage.private === true;
const canReply = conversation.can_reply !== false;

const rawContentType = clean(body.content_type || primaryMessage.content_type || "text");

const attachments = Array.isArray(body.attachments)
  ? body.attachments
  : Array.isArray(primaryMessage.attachments)
    ? primaryMessage.attachments
    : [];

const hasAttachment = attachments.length > 0;
const firstAttachment = attachments[0] || {};

const dataUrl = firstFilled(
  firstAttachment.data_url,
  firstAttachment.download_url,
  firstAttachment.file_url,
  firstAttachment.url
) || null;

const content = cleanText(
  firstFilled(
    body.content,
    body.messages?.[0]?.content,
    primaryMessage.processed_message_content,
    primaryMessage.content
  )
);

const hasText = content.length > 0;

const mediaType = hasAttachment
  ? clean(firstAttachment.file_type || firstAttachment.type || firstAttachment.content_type || "attachment").toLowerCase()
  : "none";

const messageModality = hasAttachment && hasText
  ? `${mediaType}_with_text`
  : hasAttachment
    ? `${mediaType}_only`
    : hasText
      ? "text_only"
      : "unknown";

if (event && event !== "message_created") {
  return ignored("evento_nao_message_created");
}

if (!isIncoming) {
  return ignored("mensagem_nao_incoming", {
    message_type: messageType,
    sender_type: senderType,
  });
}

if (isPrivate) {
  return ignored("mensagem_privada");
}

if (!canReply) {
  return ignored("conversa_sem_permissao_de_resposta");
}

if (hasOptoutLabel) {
  return ignored("label_99_optout", { labels });
}

if (hasHumanLabel) {
  return ignored("label_humano_assumiu", { labels });
}

if (!hasJuliaLabel) {
  return ignored("sem_label_julia", { labels });
}

if (!shouldProcessByLabels) {
  return ignored("labels_nao_permitem_julia", { labels });
}

if (!content && !hasAttachment) {
  return ignored("mensagem_sem_texto_e_sem_anexo");
}

const accountId = body.account?.id || conversation.account_id || null;
const inboxId = body.inbox?.id || conversation.inbox_id || null;
const conversationId = conversation.id || primaryMessage.conversation_id || null;
const contactId = sender.id || primaryMessage.sender_id || conversation.meta?.sender?.id || null;

const phone = onlyDigits(
  firstFilled(
    sender.phone_number,
    sender.identifier,
    primaryMessage.sender?.phone_number
  )
);

const sessionKey = phone || contactId || conversationId || body.id || Date.now();
const sessionId = `julia-chatwoot-a${accountId || "x"}-${sessionKey}`;

const contactName = firstFilled(sender.name, conversation.meta?.sender?.name);

const attachmentSummary = hasAttachment
  ? attachments.map((attachment, index) => {
      const kind = firstFilled(
        attachment.file_type,
        attachment.content_type,
        attachment.message_type,
        "anexo"
      );

      const url = firstFilled(
        attachment.data_url,
        attachment.download_url,
        attachment.file_url,
        attachment.url
      );

      return `Anexo ${index + 1}: ${kind}${url ? ` - ${url}` : ""}`;
    }).join("\n")
  : "";

const safeContent = content
  ? [
      content,
      attachmentSummary ? `\n\nContexto de mídia recebida:\n${attachmentSummary}` : "",
    ].join("").trim()
  : `[Mensagem com anexo sem legenda. message_modality=${messageModality || "unknown"}]`;

const custom = sender.custom_attributes || {};
const additional = conversation.additional_attributes || {};

const companyName = firstFilled(
  custom.empresa,
  custom.company_name,
  custom.nome_empresa,
  additional.empresa,
  additional.company_name
);

const leadNiche = firstFilled(
  custom.nicho,
  custom.segmento,
  additional.nicho,
  additional.segmento
);

const googleRating = firstFilled(
  custom.classificacao,
  custom.nota_google,
  custom.google_rating,
  additional.classificacao,
  additional.nota_google
);

const googleReviews = firstFilled(
  custom.avaliacoes,
  custom.google_reviews,
  additional.avaliacoes,
  additional.google_reviews
);

const googleBusinessProfile = firstFilled(
  custom.gmn,
  custom.google_business_profile,
  custom.link_gmn,
  additional.gmn,
  additional.google_business_profile,
  additional.link_gmn
);

const cityState = firstFilled(
  custom.cidade_estado,
  custom.cidade,
  additional.cidade_estado,
  additional.cidade
);

const origem = firstFilled(
  custom.origem,
  additional.origem,
  leadSource.source_type
);

const campanha = firstFilled(custom.campanha, additional.campanha);
const anuncio = firstFilled(custom.anuncio, additional.anuncio);

const linkRastreavel = firstFilled(
  custom.link_rastreavel,
  additional.link_rastreavel
);

return [{
  json: {
    action: "agent",
    sessionId,
    chatInput: safeContent,

    lead: {
      id: contactId || sessionKey,
      name: contactName,
      phone,

      company_name: companyName,
      niche: leadNiche,
      city_state: cityState,

      google_rating: googleRating,
      google_reviews: googleReviews,
      google_business_profile: googleBusinessProfile,

      origem,
      campanha,
      anuncio,
      link_rastreavel: linkRastreavel,

      source: leadSource.source_type,
      source_type: leadSource.source_type,
      source_label: leadSource.source_label,
      source_description: leadSource.source_description,

      current_stage: "descoberta",
      responsible_name: "",
      responsible_phone: "",
      fit_score: null,
      lead_status: "EM_ANDAMENTO",
    },

    message: {
      role: "lead",
      content,
      content_for_ai: safeContent,

      has_text: hasText,
      has_attachment: hasAttachment,

      content_type: messageModality,
      message_modality: messageModality,
      raw_content_type: rawContentType,

      data_url: dataUrl,
      media_type: mediaType,

      created_at: firstFilled(body.created_at, primaryMessage.updated_at, nowIso()),
    },

    conversation: {
      is_test: false,
      memory_enabled: true,
      history_source: "chatwoot_subworkflow",

      labels,
      has_julia_label: hasJuliaLabel,
      has_human_label: hasHumanLabel,
      has_optout_label: hasOptoutLabel,

      lead_source_type: leadSource.source_type,
      source_label: leadSource.source_label,
      playbook_mode: leadSource.playbook_mode,

      status: clean(conversation.status),
      unread_count: conversation.unread_count || 0,
      assignee_id: conversation.assignee_id || null,
      team_id: conversation.meta?.team?.id || null,
      team_name: conversation.meta?.team?.name || "",
    },

    chatwoot: {
      account_id: accountId,
      inbox_id: inboxId,
      conversation_id: conversationId,
      contact_id: contactId,
      message_id: body.id || primaryMessage.id || null,
      source_id: firstFilled(body.source_id, primaryMessage.source_id),
      delivery_id: headers["x-chatwoot-delivery"] || "",
      webhook_url: envelope.webhookUrl || "",
      raw_event: event || "message_created",
    },

    routing: {
      should_process: true,
      should_reply: true,
      should_handoff: false,
      route_action: "agent",
      direct_handoff_motivo: "",
      channel: "chatwoot_whatsapp",
      agent_name: "Julia",
    },

    labels_update: {
      add: [],
      remove: [],
    },

    agent: {
      memory_session_id: sessionId,

      lead_source_type: leadSource.source_type,
      source_label: leadSource.source_label,
      playbook_mode: leadSource.playbook_mode,
      source_description: leadSource.source_description,

      ai_input: [
        "MENSAGEM ATUAL DO LEAD:",
        safeContent,
        "",
        "ORIGEM DETECTADA POR LABEL:",
        `Tipo: ${leadSource.source_type}`,
        `Etiqueta: ${leadSource.source_label || "não informada"}`,
        `Descrição: ${leadSource.source_description}`,
      ].join("\n"),
    },

    debug: {
      normaliza_entrada_chatwoot_version: NORMALIZA_ENTRADA_CHATWOOT_VERSION,

      labels,
      labels_source: "Lista Etiquetas",

      has_julia_label: hasJuliaLabel,
      has_human_label: hasHumanLabel,
      has_optout_label: hasOptoutLabel,
      should_process_by_labels: shouldProcessByLabels,

      lead_source_type: leadSource.source_type,
      source_label: leadSource.source_label,
      playbook_mode: leadSource.playbook_mode,

      original_message_type: messageType,
      numeric_message_type: numericMessageType,
      sender_type: senderType,

      has_attachment: hasAttachment,
      content_type: messageModality,
      message_modality: messageModality,

      data_url: dataUrl,
    },
  },
}];

