  } else if (typeof value === "object") {
    try {
      text = JSON.stringify(value);
    } catch (error) {
      text = "";
    }
  } else {
    text = String(value);
  }

  text = text
    .replace(/\[object Object\]/gi, "")
    .replace(/[\u200B-\u200D\u2060\uFEFF]/g, " ")
    .replace(/\uFFFD/g, " ")
    .replace(/\r\n/g, "\n")
    .replace(/\r/g, "\n");

  if (preserveNewLines) {
    return text
      .split("\n")
      .map(line => line.replace(/[ \t]+/g, " ").trim())
      .filter(Boolean)
      .join("\n")
      .trim();
  }

  return text.replace(/\s+/g, " ").trim();
}

function asObject(value) {
  return value && typeof value === "object" && !Array.isArray(value) ? value : {};
}

function firstFilled(...values) {
  for (const value of values) {
    const text = clean(value, true);
    if (text) return text;
  }
  return "";
}

function extractInterpretedMessage(data) {
  const msg = data?.message;

  if (typeof msg === "string") {
    return { content: clean(msg, true) };
  }

  if (msg && typeof msg === "object") {
    return {
      ...msg,
      content: firstFilled(
        msg.content,
        msg.text,
        msg.transcription,
        msg.transcribed_text,
        msg.interpreted_message,
        msg.message
      ),
    };
  }

  return {
    content: firstFilled(
      data?.content,
      data?.text,
      data?.transcription,
      data?.transcribed_text,
      data?.interpreted_message,
      data?.output,
      data?.message
    ),
  };
}

function detectLeadSourceType(entrada, current) {
  return firstFilled(
    entrada.agent?.lead_source_type,
    entrada.agent?.playbook_mode,
    entrada.lead?.source_type,
    entrada.lead?.source,
    entrada.conversation?.lead_source_type,
    entrada.conversation?.playbook_mode,

    current.agent?.lead_source_type,
    current.agent?.playbook_mode,
    current.lead?.source_type,
    current.lead?.source,
    current.conversation?.lead_source_type,
    current.conversation?.playbook_mode,

    "indefinido"
  );
}

function buildKnowledgeQuery({ leadSourceType, finalContent, historyForAgent, lead }) {
  return [
    `Modo de atendimento: ${leadSourceType}`,
    "",
    "Mensagem atual do lead:",
    finalContent || "sem mensagem textual",
    "",
    "Dados disponíveis do lead:",
    `Nome do contato: ${lead.name || "não informado"}`,
    `Empresa: ${lead.company_name || "não informado"}`,
    `Nicho: ${lead.niche || "não informado"}`,
    `Cidade/UF: ${lead.city_state || "não informado"}`,
    `Nota Google: ${lead.google_rating || "não informado"}`,
    `Avaliações Google: ${lead.google_reviews || "não informado"}`,
    "",
    "Histórico recente:",
    historyForAgent || "sem histórico recente"
  ]
    .join("\n")
    .slice(0, 4000);
}

const entrada = readNode("Normaliza Entrada Chatwoot");
const interpretacao = readNode("Interpreta Audio ou Texto");
const historico = readNode("Busca Histórico Chatwoot");

const baseMessage = asObject(entrada.message || $json.message);
const interpretedMessage = extractInterpretedMessage(interpretacao);

const baseContent = clean(baseMessage.content, true);
const baseContentForAi = clean(baseMessage.content_for_ai, true);
const interpretedContent = clean(interpretedMessage.content, true);

const finalContent = firstFilled(
  interpretedContent,
  baseContent,
  baseContentForAi,
  entrada.chatInput,
  $json.chatInput
);

const historyForAgent = clean(
  historico.history_for_agent ||
  entrada.agent?.history_for_agent ||
  $json.agent?.history_for_agent,
  true
);

const lead = asObject(entrada.lead || $json.lead);
const leadSourceType = detectLeadSourceType(entrada, $json);

const baseSearchQuery = buildKnowledgeQuery({
  leadSourceType,
  finalContent,
  historyForAgent,
  lead
});

const message = {
  ...baseMessage,
  ...interpretedMessage,

  content: finalContent,
  content_raw: baseContent,
  content_before_interpretation: baseContent,
  content_for_ai: finalContent,

  has_text: Boolean(finalContent),
  has_attachment: baseMessage.has_attachment === true,

  content_type:
    baseMessage.content_type ||
    baseMessage.message_modality ||
    interpretedMessage.content_type ||
    interpretedMessage.message_modality ||
    "text_only",

  message_modality:
    baseMessage.message_modality ||
    baseMessage.content_type ||
    interpretedMessage.message_modality ||
    interpretedMessage.content_type ||
    "text_only",

  data_url: baseMessage.data_url || interpretedMessage.data_url || null,
  media_type: baseMessage.media_type || interpretedMessage.media_type || "",
};

return [
  {
    json: {
      ...$json,
      ...entrada,

      message,

      agent: {
        ...asObject(entrada.agent),
        ...asObject($json.agent),

        lead_source_type: leadSourceType,
        playbook_mode: leadSourceType,

        history_for_agent: historyForAgent,
        history_source: "chatwoot_subworkflow",

        current_message_after_interpretation: finalContent,

        needs_business_knowledge: true,
        business_knowledge_intents: [],
        searchable_knowledge_intents: [],

        handoff_recommended: false,
        handoff_reasons: [],
        next_recommended_step: "",

        knowledge_query: baseSearchQuery,
      },

      routing: {
        ...asObject(entrada.routing),
        ...asObject($json.routing),

        handoff_recommended: false,
        handoff_reasons: [],
        next_recommended_step: "",
      },

      chatInput: finalContent,

      should_search_knowledge_base: true,
      base_search_query: baseSearchQuery,

      debug: {
        ...asObject($json.debug),

        monta_query_julia_version: NODE_VERSION,

        lead_source_type: leadSourceType,
        playbook_mode: leadSourceType,

        base_content: baseContent,
        interpreted_content: interpretedContent,
        final_content: finalContent,

        has_history_for_agent: Boolean(historyForAgent),

        needs_business_knowledge: true,
        business_knowledge_intents: [],
        searchable_knowledge_intents: [],

        handoff_recommended: false,
        handoff_reasons: [],

        base_search_query: baseSearchQuery,
      },
    },
  },
];

const NODE_VERSION = "v5_clean_trust_agent_json_only";

const HUMAN_LABEL = "01-humano-assumiu";
const JULIA_LABEL = "01-julia-conversando";
const OPTOUT_LABEL = "99-optout";

function readNode(name) {
  try {
    return $(name).first().json || {};
  } catch (error) {
    return {};
  }
}

function clean(value, preserveNewLines = false) {
  let text = "";

  if (value === undefined || value === null) {
    text = "";
  } else if (typeof value === "object") {
    try {
      text = JSON.stringify(value);
    } catch (error) {
      text = "";
    }
  } else {
    text = String(value);
  }

  text = text
    .replace(/\[object Object\]/gi, "")
    .replace(/[\u200B-\u200D\u2060\uFEFF]/g, " ")
    .replace(/\uFFFD/g, " ")
    .replace(/\r\n/g, "\n")
    .replace(/\r/g, "\n");

  if (preserveNewLines) {
    return text
      .split("\n")
      .map(line => line.replace(/[ \t]+/g, " ").trim())
      .filter(Boolean)
      .join("\n")
      .trim();
  }

  return text.replace(/\s+/g, " ").trim();
}

function asObject(value) {
  return value && typeof value === "object" && !Array.isArray(value) ? value : {};
}

function asArray(value) {
  return Array.isArray(value) ? value : [];
}

function firstFilled(...values) {
  for (const value of values) {
    const text = clean(value, true);
    if (text) return text;
  }
  return "";
}

function toBoolean(value, defaultValue = false) {
  if (value === true) return true;
  if (value === false) return false;

  const text = clean(value).toLowerCase();

  if (["true", "sim", "yes", "1"].includes(text)) return true;
  if (["false", "nao", "não", "no", "0"].includes(text)) return false;

  return defaultValue;
}

function toNumber(value, defaultValue = 0) {
  const n = Number(value);
  return Number.isFinite(n) ? n : defaultValue;
}

function clamp(value, min, max) {
  const n = toNumber(value, min);
  return Math.max(min, Math.min(max, n));
}

function uniqueStrings(values) {
  return [...new Set(
    asArray(values)
      .map(value => clean(value))
      .filter(Boolean)
  )];
}

function addUnique(arr, value) {
  const text = clean(value);
  if (text && !arr.includes(text)) arr.push(text);
}

function removeValue(arr, value) {
  return asArray(arr).filter(item => item !== value);
}

function parseJsonOutput(raw) {
  if (raw && typeof raw === "object" && !Array.isArray(raw)) {
    return {
      ok: true,
      data: raw,
      raw: JSON.stringify(raw),
      error: ""
    };
  }

  let text = clean(raw, true);

  text = text
    .replace(/^```json\s*/i, "")
    .replace(/^```\s*/i, "")
    .replace(/```$/i, "")
    .trim();

  try {
    return {
      ok: true,
      data: JSON.parse(text),
      raw: text,
      error: ""
    };
  } catch (error) {
    const match = text.match(/\{[\s\S]*\}/);

    if (match) {
      try {
        return {
          ok: true,
          data: JSON.parse(match[0]),
          raw: text,
          error: ""
        };
      } catch (innerError) {
        return {
          ok: false,
          data: {},
          raw: text,
          error: innerError.message
        };
      }
    }

    return {
      ok: false,
      data: {},
      raw: text,
      error: error.message
    };
  }
}

function normalizeStatus(status) {
  const allowed = new Set([
    "EM_ANDAMENTO",
    "AGUARDANDO_RESPONSAVEL",
    "INTERESSADO",
    "PEDIU_PRECO",
    "PEDIU_PROPOSTA",
    "PEDIU_REUNIAO",
    "PEDIU_DIAGNOSTICO",
    "QUALIFICADO_HUMANO",
    "SEM_INTERESSE",
    "SEM_FIT",
    "OPT_OUT",
    "JA_TEM_AGENCIA",
    "INDICACAO_POTENCIAL"
  ]);

  const value = clean(status).toUpperCase();

  return allowed.has(value) ? value : "EM_ANDAMENTO";
}

const preJulia = readNode("NORMALIZA PRE JULIA");
const entrada = readNode("Normaliza Entrada Chatwoot");

const current = $json || {};

const rawOutput = firstFilled(
  current.output,
  current.text,
  current.response,
  current.result,
  current.message,
  current
);

const parsed = parseJsonOutput(rawOutput);
const out = asObject(parsed.data);

const lead = asObject(preJulia.lead || entrada.lead);
const message = asObject(preJulia.message || entrada.message);
const conversation = asObject(preJulia.conversation || entrada.conversation);
const chatwoot = asObject(preJulia.chatwoot || entrada.chatwoot);
const routingOriginal = asObject(preJulia.routing || entrada.routing);
const agentOriginal = asObject(preJulia.agent || entrada.agent);

let respostaFinal = firstFilled(out.resposta);
let status = normalizeStatus(out.status);

let deveResponder = parsed.ok ? toBoolean(out.deve_responder, true) : false;
let handoffHumano = parsed.ok ? toBoolean(out.handoff_humano, false) : false;

let motivoHandoff = firstFilled(out.motivo_handoff);

let tagsAdicionar = uniqueStrings(out.tags_adicionar);
let tagsRemover = uniqueStrings(out.tags_remover);

const score = clamp(out.score_de_0_a_100, 0, 100);

const leadSourceType = firstFilled(
  out.lead_source_type,
  agentOriginal.lead_source_type,
  lead.source_type,
  lead.source,
  conversation.lead_source_type
);

if (!parsed.ok) {
  status = "EM_ANDAMENTO";
  deveResponder = false;
  handoffHumano = false;
  respostaFinal = "";
  motivoHandoff = "";
  tagsAdicionar = [];
  tagsRemover = [];
}

const optoutDetected = status === "OPT_OUT";

if (optoutDetected) {
  respostaFinal = "Claro, sem problema. Não vou te chamar novamente por aqui.";
  deveResponder = true;
  handoffHumano = false;

  tagsAdicionar = [];
  tagsRemover = [];

  addUnique(tagsAdicionar, OPTOUT_LABEL);
  addUnique(tagsRemover, JULIA_LABEL);
}

const agentAskedHumanLabel =
  tagsAdicionar.includes(HUMAN_LABEL) ||
  tagsRemover.includes(JULIA_LABEL);

const handoffRequested =
  !optoutDetected &&
  parsed.ok &&
  (
    handoffHumano === true ||
    agentAskedHumanLabel === true
  );

if (handoffRequested) {
  handoffHumano = true;

  addUnique(tagsAdicionar, HUMAN_LABEL);
  addUnique(tagsRemover, JULIA_LABEL);

  if (!motivoHandoff) {
    motivoHandoff = "handoff_solicitado_pela_julia";
  }

  if (!respostaFinal) {
    respostaFinal = "Entendi. Vou pedir para uma pessoa da equipe continuar com você por aqui.";
  }
} else if (!optoutDetected) {
  handoffHumano = false;
  motivoHandoff = "";

  tagsAdicionar = removeValue(tagsAdicionar, HUMAN_LABEL);
  tagsRemover = removeValue(tagsRemover, JULIA_LABEL);
}

tagsAdicionar = uniqueStrings(tagsAdicionar);
tagsRemover = uniqueStrings(tagsRemover);

const shouldReply =
  parsed.ok &&
  deveResponder === true &&
  Boolean(respostaFinal);

let action = "ignore";

if (optoutDetected) {
  action = "optout";
} else if (handoffRequested) {
  action = "handoff";
} else if (shouldReply) {
  action = "reply";
} else {
  action = "ignore";
}

const routingDecision = {
  next_action: action,
  reason: parsed.ok
    ? handoffRequested
      ? motivoHandoff || "handoff_solicitado_pela_julia"
      : optoutDetected
        ? "optout_detectado_pela_julia"
        : shouldReply
          ? "resposta_normal"
          : "julia_nao_deve_responder"
    : `falha_parse_json: ${parsed.error || "erro_desconhecido"}`,

  handoff_required: handoffRequested,
  remove_julia: handoffRequested || optoutDetected,
  add_human_label: handoffRequested,
  send_human_phone: false,
  human_phone: "",

  optout_detected: optoutDetected,
  parse_ok: parsed.ok,
};

const agentResult = {
  resposta: respostaFinal,
  deve_responder: shouldReply,
  handoff_humano: handoffHumano,
  motivo_handoff: motivoHandoff,

  status,
  lead_source_type: leadSourceType,

  nome_responsavel: firstFilled(out.nome_responsavel),
  empresa: firstFilled(out.empresa),
  origem_clientes: firstFilled(out.origem_clientes),
  principal_gargalo: firstFilled(out.principal_gargalo),
  interesse_em_crescer: firstFilled(out.interesse_em_crescer),

  tem_agencia:
    out.tem_agencia === null || out.tem_agencia === undefined
      ? null
      : toBoolean(out.tem_agencia, false),

  score_de_0_a_100: score,
  motivo_score: firstFilled(out.motivo_score),

  resumo_conversa: firstFilled(out.resumo_conversa),
  proximo_passo: firstFilled(out.proximo_passo),

  tags_adicionar: tagsAdicionar,
  tags_remover: tagsRemover,

  observacoes: firstFilled(out.observacoes),

  routing_decision: routingDecision,

  parse_ok: parsed.ok,
  parse_error: parsed.error,
  raw_output: parsed.raw
};

return [
  {
    json: {
      action,
      sessionId: preJulia.sessionId || entrada.sessionId || "",

      chatInput: respostaFinal,
      resposta_final: respostaFinal,
      message_to_send: respostaFinal,

      should_reply: shouldReply,
      should_handoff: handoffHumano,

      routing_decision: routingDecision,

      lead: {
        ...lead,

        source_type: lead.source_type || leadSourceType,
        source: lead.source || leadSourceType,

        responsible_name:
          agentResult.nome_responsavel ||
          lead.responsible_name ||
          "",

        responsible_phone:
          lead.responsible_phone ||
          entrada.lead?.responsible_phone ||
          "",

        fit_score: score,
        lead_status: status,

        empresa_detectada:
          agentResult.empresa ||
          lead.company_name ||
          "",

        origem_clientes: agentResult.origem_clientes,
        principal_gargalo: agentResult.principal_gargalo,
        interesse_em_crescer: agentResult.interesse_em_crescer,
        tem_agencia: agentResult.tem_agencia,
      },

      message,
      conversation,
      chatwoot,

      routing: {
        ...routingOriginal,

        should_process: true,
        should_reply: shouldReply,
        should_handoff: handoffHumano,

        route_action: action,
        direct_handoff_motivo: motivoHandoff || routingDecision.reason,

        routing_decision: routingDecision,

        channel: "chatwoot_whatsapp",
        agent_name: "Julia",
      },

      agent: {
        ...agentOriginal,

        result: agentResult,
        final_response: respostaFinal,
        lead_status: status,
        handoff_humano: handoffHumano,
        motivo_handoff: motivoHandoff,
        routing_decision: routingDecision,
      },

      crm_update: {
        contact_id: chatwoot.contact_id || lead.id || null,
        conversation_id: chatwoot.conversation_id || null,
        phone: lead.phone || "",

        lead_status: status,
        fit_score: score,
        lead_source_type: leadSourceType,

        nome_responsavel: agentResult.nome_responsavel,
        telefone_responsavel:
          lead.responsible_phone ||
          entrada.lead?.responsible_phone ||
          "",

        empresa: agentResult.empresa,
        origem_clientes: agentResult.origem_clientes,
        principal_gargalo: agentResult.principal_gargalo,
        interesse_em_crescer: agentResult.interesse_em_crescer,
        tem_agencia: agentResult.tem_agencia,

        motivo_score: agentResult.motivo_score,
        resumo_conversa: agentResult.resumo_conversa,
        proximo_passo: agentResult.proximo_passo,
        observacoes: agentResult.observacoes,

        routing_next_action: routingDecision.next_action,
        routing_reason: routingDecision.reason,
        handoff_required: routingDecision.handoff_required,
      },

      labels_update: {
        add: tagsAdicionar,
        remove: tagsRemover,
      },

      parsed_output: agentResult,

      debug: {
        ...(preJulia.debug || {}),

        normaliza_saida_julia_version: NODE_VERSION,

        parse_ok: parsed.ok,
        parse_error: parsed.error,

        status,
        lead_source_type: leadSourceType,

        should_reply: shouldReply,
        should_handoff: handoffHumano,

        action,
        route_action: action,

        routing_decision: routingDecision,

        tags_adicionar: tagsAdicionar,
        tags_remover: tagsRemover,

        raw_output: parsed.raw,
      }
    }
  }
];

